const body = $input.first().json.body || $input.first().json;
const text = body.transcript || body.text || body.command || '';
const source = body.source || 'voice-bridge';
// Auto-detect tower
const t = text.toLowerCase();
let tower = 'max';
if (/build|code|deploy|script|api|worker/.test(t)) tower = 'code';
else if (/consent|revoke|never.*clause|rights/.test(t)) tower = 'cb01';
else if (/vision|future|epoch|strategy/.test(t)) tower = 'dream';
else if (/family|pops|shirl|wellbeing/.test(t)) tower = 'pops';
else if (/music|voice|audio|sing|perform/.test(t)) tower = 'lucy';
return [{ json: { text, source, tower, ts: new Date().toISOString() } }];
